module RefModule(clk, Reset, PCWre, nextAddress, Address);input clk, Reset, PCWre;
    input [31:0] nextAddress;
    output reg [31:0] Address;
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)begin
        if (Reset == 0)
            Address = 0;
        else if(PCWre==1)
            Address = nextAddress;
    end
endmodule
